#!/bin/bash
set -euo pipefail

# One-time per-clone setup for developer workstations.
#
# Wires up pre-commit (the regular pre-commit stage plus the post-merge
# and post-rewrite stages used by the codesight regen hooks), then seeds
# the autogenerated codesight context maps so they exist on disk before
# the first `git pull`.
#
# Run from the repo root:
#   ./scripts/setup-dev.sh
#
# Re-running is safe — pre-commit install is idempotent, and the codesight
# regen overwrites in place.

# Pre-commit installs all three hook types per `default_install_hook_types`
# in .pre-commit-config.yaml — no -t flag needed.
pre-commit install

# Seed the codesight maps. Without this, .codesight/ is empty until the
# first post-merge fires.
pre-commit run --all-files --hook-stage post-merge
